class Solution:
    def sortString(self, s: str) -> str:
        from collections import Counter
        cnt = Counter(s)
        keys = sorted(cnt)
        res = []
        total = len(s)
        while len(res) < total:
            for k in keys:
                if cnt[k]:
                    res.append(k)
                    cnt[k] -= 1
            for k in reversed(keys):
                if cnt[k]:
                    res.append(k)
                    cnt[k] -= 1
        return ''.join(res)
```
